// ECommerce.Domain/Entities/Order.cs
namespace ECommerce.Domain.Entities;

public class Order
{
    public Guid Id { get; private set; }
    public Guid CustomerId { get; private set; }
    public IReadOnlyList<OrderItem> Items { get; private set; }
    public OrderStatus Status { get; private set; }

    private Order() { } // EF Core constructor

    public static Order Create(Guid customerId, IEnumerable<OrderItem> items)
    {
        if (!items.Any()) throw new DomainException("Order must have at least one item.");
        return new Order
        {
            Id = Guid.NewGuid(),
            CustomerId = customerId,
            Items = items.ToList().AsReadOnly(),
            Status = OrderStatus.Pending
        };
    }

    public void Place()
    {
        if (Status != OrderStatus.Pending) throw new DomainException("Can only place pending orders.");
        Status = OrderStatus.Placed;
    }

    public void Cancel()
    {
        if (Status == OrderStatus.Shipped) throw new DomainException("Cannot cancel shipped orders.");
        Status = OrderStatus.Cancelled;
    }
}

// ECommerce.Domain.Services/OrderPricingService.cs
using ECommerce.Domain.Entities;
using ECommerce.Domain.ValueObjects;

namespace ECommerce.Domain.Services;

/// <summary>Domain service for pricing logic spanning Order and Promotion.</summary>
public class OrderPricingService
{
    public Money CalculateFinalPrice(Order order, IEnumerable<Promotion> promotions)
    {
        var basePrice = order.Items.Aggregate(Money.Zero, (sum, item) => sum.Add(item.Subtotal));
        var discount = promotions
            .Where(p => p.IsApplicableTo(order))
            .Aggregate(Money.Zero, (sum, p) => sum.Add(p.CalculateDiscount(basePrice)));
        return basePrice.Subtract(discount);
    }
}

// ECommerce.Application/Services/OrderApplicationService.cs
using ECommerce.Domain.Entities;
using ECommerce.Domain.Interfaces;
using ECommerce.Domain.Services;
using ECommerce.Application.DTOs;
using ECommerce.Application.Interfaces;

namespace ECommerce.Application.Services;

public class OrderApplicationService
{
    private readonly IOrderRepository _orderRepository;
    private readonly IEmailService _emailService;
    private readonly OrderPricingService _pricingService;

    public OrderApplicationService(
        IOrderRepository orderRepository,
        IEmailService emailService,
        OrderPricingService pricingService)
    {
        _orderRepository = orderRepository;
        _emailService = emailService;
        _pricingService = pricingService;
    }

    public async Task<OrderDto> PlaceOrderAsync(PlaceOrderRequest request)
    {
        var order = Order.Create(request.CustomerId, request.Items.Select(/* map */));
        var price = _pricingService.CalculateFinalPrice(order, request.ApplicablePromotions);
        order.Place();
        await _orderRepository.SaveAsync(order);
        await _emailService.SendOrderConfirmationAsync(order, price);
        return OrderDto.FromOrder(order, price);
    }
}
